#include <stdio.h>
#include <stdlib.h>

long long sumOfSubarrayRanges(int* inputArray, int n) {
    long long totalSum = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i; j < n; j++) {
            int max = inputArray[i];
            int min = inputArray[i];
            for (int k = i; k <= j; k++) {
                if (inputArray[k] > max) max = inputArray[k];
                if (inputArray[k] < min) min = inputArray[k];
            }
            totalSum += max - min;
        }
    }
    return totalSum;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int* inputArray = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &inputArray[i]);
        }
        printf("%lld\n", sumOfSubarrayRanges(inputArray, n));
        free(inputArray);
    }
    return 0;
}

