import java.util.Scanner;

public class Main {
    public static long sumOfSubarrayRanges(int[] inputArray) {
        int n = inputArray.length;
        long totalSum = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                int max = inputArray[i];
                int min = inputArray[i];
                for (int k = i; k <= j; k++) {
                    if (inputArray[k] > max) max = inputArray[k];
                    if (inputArray[k] < min) min = inputArray[k];
                }
                totalSum += max - min;
            }
        }
        return totalSum;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            int[] inputArray = new int[n];
            for (int i = 0; i < n; i++) {
                inputArray[i] = scanner.nextInt();
            }
            System.out.println(sumOfSubarrayRanges(inputArray));
        }
    }
}

